function solve(c: number, connections: number[][], queries: number[][]): number[] {
    // Build the graph
    const graph: number[][] = Array.from({ length: c + 1 }, () => []);
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // Union-Find (Disjoint Set Union) data structure
    class DSU {
        parent: number[];
        rank: number[];
        constructor(size: number) {
            this.parent = Array.from({ length: size + 1 }, (_, i) => i);
            this.rank = Array.from({ length: size + 1 }, () => 1);
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);
            if (xRoot === yRoot) return false;
            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    const dsu = new DSU(c);
    for (const [u, v] of connections) {
        dsu.union(u, v);
    }

    // For each component, keep track of the minimum id
    const componentMin: Map<number, number> = new Map();
    for (let i = 1; i <= c; i++) {
        const root = dsu.find(i);
        if (!componentMin.has(root)) {
            componentMin.set(root, i);
        }
    }

    // Track which nodes are online
    const online: boolean[] = Array(c + 1).fill(true);

    const result: number[] = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                const minId = componentMin.get(root);
                if (minId !== undefined && online[minId]) {
                    result.push(minId);
                } else {
                    result.push(-1);
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}

