public static long[] solve(long c, long[][] connections, long[][] queries) {
    // Build the graph
    ArrayList<Long>[] graph = new ArrayList[(int) (c + 1)];
    for (long i = 1; i <= c; i++) {
        graph[i] = new ArrayList<>();
    }
    for (long[] connection : connections) {
        long u = connection[0];
        long v = connection[1];
        graph[(int) u].add(v);
        graph[(int) v].add(u);
    }

    // Union-Find (Disjoint Set Union) data structure
    class DSU {
        long[] parent;
        long[] rank;
        public DSU(long size) {
            parent = new long[(int) (size + 1)];
            rank = new long[(int) (size + 1)];
            for (long i = 0; i <= size; i++) {
                parent[i] = i;
                rank[i] = 1;
            }
        }

        long find(long x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        boolean union(long x, long y) {
            long xRoot = find(x);
            long yRoot = find(y);
            if (xRoot == yRoot) return false;
            if (rank[xRoot] < rank[yRoot]) {
                parent[xRoot] = yRoot;
            } else {
                parent[yRoot] = xRoot;
                if (rank[xRoot] == rank[yRoot]) {
                    rank[xRoot]++;
                }
            }
            return true;
        }
    }

    DSU dsu = new DSU(c);
    for (long[] connection : connections) {
        long u = connection[0];
        long v = connection[1];
        dsu.union(u, v);
    }

    // For each component, keep track of the minimum id
    HashMap<Long, Long> componentMin = new HashMap<>();
    for (long i = 1; i <= c; i++) {
        long root = dsu.find(i);
        if (!componentMin.containsKey(root)) {
            componentMin.put(root, i);
        }
    }

    // Track which nodes are online
    boolean[] online = new boolean[(int) (c + 1)];
    for (long i = 1; i <= c; i++) {
        online[(int) i] = true;
    }

    long[] result = new long[queries.length];
    int idx = 0;

    for (long[] query : queries) {
        long type = query[0];
        long x = query[1];
        if (type == 1) {
            if (online[(int) x]) {
                result[idx++] = x;
            } else {
                long root = dsu.find(x);
                Long minId = componentMin.get(root);
                if (minId != null && online[(int) minId]) {
                    result[idx++] = minId;
                } else {
                    result[idx++] = -1;
                }
            }
        } else {
            online[(int) x] = false;
        }
    }

    return result;
}
